mapper.select:
SELECT DISTINCT ba.user_id FROM business_menu bm LEFT JOIN business_role_menu brm ON bm.id = brm.menu_id LEFT JOIN business_role br ON brm.role_id = br.id LEFT JOIN business_admin_role bar ON br.id = bar.role_id LEFT JOIN business_admin ba ON bar.admin_id = ba.id WHERE bm.menu_key IN
#{item}
AND bm.business_system = 'SITE' AND br.site_code = #{siteCode}
UNION
SELECT DISTINCT ba.user_id FROM business_admin ba WHERE ba.is_super_admin = 1 AND ba.site_code = #{siteCode}
ORDER BY user_id ASC
